import{ab as l,G as n,H as s,E as e,U as o,N as a,ac as h,ad as c,X as d}from"./framework-756f1659.js";const r={},u=c('<div class="hint-container warning"><p class="hint-container-title">注意</p><p>本文部分内容来自网络。侵删。</p></div><h2 id="容器概述" tabindex="-1"><a class="header-anchor" href="#容器概述" aria-hidden="true">#</a> 容器概述</h2><p>Java 集合， 也叫作容器，主要是由两大接口派生而来：一个是 <code>Collection</code>接口，主要用于存放单一元素；另一个是 <code>Map</code> 接口，主要用于存放键值对。对于<code>Collection</code> 接口，下面又有三个主要的子接口：<code>List</code>、<code>Set</code> 和 <code>Queue</code>。主要接口和实现类如下图所示。</p><figure><img src="https://fastly.jsdelivr.net/gh/jayxiaohe/blog_img/img/20220328225601.png" alt="20220327132758" tabindex="0" loading="lazy"><figcaption>20220327132758</figcaption></figure><blockquote><p><em>图中只列举了主要的继承派生关系，并没有列举所有关系。</em></p></blockquote><h2 id="list-set-queue-map-四者的区别" tabindex="-1"><a class="header-anchor" href="#list-set-queue-map-四者的区别" aria-hidden="true">#</a> List, Set, Queue, Map 四者的区别？</h2><ul><li><p><code>List</code>存储的元素是有序的、可重复的。</p></li><li><p><code>Set</code>存储的元素是无序的、不可重复的。</p></li><li><p><code>Queue</code>按特定的排队规则来确定先后顺序，存储的元素是有序的、可重复的。</p></li><li><p><code>Map</code>使用键值对（key-value）存储。key 是无序的、不可重复的，value 是无序的、可重复的，每个键最多映射到一个值。</p></li><li></li></ul><h2 id="如何选用集合" tabindex="-1"><a class="header-anchor" href="#如何选用集合" aria-hidden="true">#</a> 如何选用集合？</h2><p>主要根据集合的特点来选用，比如我们需要根据键值获取到元素值时就选用 <code>Map</code> 接口下的集合，需要排序时选择 <code>TreeMap</code>,不需要排序时就选择 <code>HashMap</code>,需要保证线程安全就选用 <code>ConcurrentHashMap</code>。</p><p>当我们只需要存放元素值时，就选择实现<code>Collection</code> 接口的集合，需要保证元素唯一时选择实现 <code>Set</code> 接口的集合比如 <code>TreeSet</code> 或 <code>HashSet</code>，不需要就选择实现 <code>List</code> 接口的比如 <code>ArrayList</code> 或 <code>LinkedList</code>，然后再根据实现这些接口的集合的特点来选用。</p><h2 id="为什么要使用集合" tabindex="-1"><a class="header-anchor" href="#为什么要使用集合" aria-hidden="true">#</a> 为什么要使用集合？</h2><p>当我们需要保存一组类型相同的数据的时候，我们应该是用一个容器来保存，这个容器就是数组，但是，使用数组存储对象具有一定的弊端， 因为我们在实际开发中，存储的数据的类型是多种多样的，于是，就出现了“集合”，集合同样也是用来存储多个数据的。</p><p>数组的缺点是一旦声明之后，长度就不可变了；同时，声明数组时的数据类型也决定了该数组存储的数据的类型；而且，数组存储的数据是有序的、可重复的，特点单一。 但是集合提高了数据存储的灵活性，Java 集合不仅可以用来存储不同类型不同数量的对象，还可以保存具有映射关系的数据。</p><h2 id="集合框架底层数据结构总结" tabindex="-1"><a class="header-anchor" href="#集合框架底层数据结构总结" aria-hidden="true">#</a> 集合框架底层数据结构总结</h2>',14),p={id:"list",tabindex:"-1"},_=e("a",{class:"header-anchor",href:"#list","aria-hidden":"true"},"#",-1),f=e("strong",null,"List",-1),H=c('<ul><li><code>Arraylist</code>： <code>Object[]</code> 数组</li><li><code>Vector</code>：<code>Object[]</code> 数组</li><li><code>LinkedList</code>： 双向链表(JDK1.6 之前为循环链表，JDK1.7 取消了循环)</li></ul><h3 id="set" tabindex="-1"><a class="header-anchor" href="#set" aria-hidden="true">#</a> Set</h3><ul><li><code>HashSet</code>(无序，唯一): 基于 <code>HashMap</code> 实现的，底层采用 <code>HashMap</code> 来保存元素</li><li><code>LinkedHashSet</code>: <code>LinkedHashSet</code> 是 <code>HashSet</code> 的子类，并且其内部是通过 <code>LinkedHashMap</code> 来实现的。有点类似于<code>LinkedHashMap</code>， 其内部是基于 <code>HashMap</code> 实现</li><li><code>TreeSet</code>(有序，唯一): 红黑树(自平衡的排序二叉树)</li></ul><h3 id="queue" tabindex="-1"><a class="header-anchor" href="#queue" aria-hidden="true">#</a> Queue</h3><ul><li><code>PriorityQueue</code>: <code>Object[]</code> 数组来实现二叉堆</li><li><code>ArrayQueue</code>: <code>Object[]</code> 数组 + 双指针</li></ul><h3 id="map" tabindex="-1"><a class="header-anchor" href="#map" aria-hidden="true">#</a> Map</h3>',6),L=e("li",null,[e("code",null,"HashMap"),o("： JDK1.8 之前 "),e("code",null,"HashMap"),o(" 由数组+链表组成的，数组是 "),e("code",null,"HashMap"),o(" 的主体，链表则是主要为了解决哈希冲突而存在的（“拉链法”解决冲突）。JDK1.8 以后在解决哈希冲突时有了较大的变化，当链表长度大于阈值（默认为 8）（将链表转换成红黑树前会判断，如果当前数组的长度小于 64，那么会选择先进行数组扩容，而不是转换为红黑树）时，将链表转化为红黑树，以减少搜索时间。")],-1),M=e("code",null,"LinkedHashMap",-1),b=e("code",null,"LinkedHashMap",-1),k=e("code",null,"HashMap",-1),m=e("code",null,"LinkedHashMap",-1),x={href:"https://www.imooc.com/article/22931",target:"_blank",rel:"noopener noreferrer"},g=e("li",null,[e("code",null,"Hashtable"),o("： 数组+链表组成的，数组是 "),e("code",null,"Hashtable"),o(" 的主体，链表则是主要为了解决哈希冲突而存在的")],-1),S=e("li",null,[e("code",null,"TreeMap"),o("： 红黑树（自平衡的排序二叉树）")],-1);function v(y,J){const i=d("RouterLink"),t=d("ExternalLinkIcon");return n(),s("div",null,[u,e("h3",p,[_,o(),a(i,{to:"/pages/list/"},{default:h(()=>[f]),_:1})]),H,e("ul",null,[L,e("li",null,[M,o("： "),b,o(" 继承自 "),k,o("，所以它的底层仍然是基于拉链式散列结构即由数组和链表或红黑树组成。另外，"),m,o(" 在上面结构的基础上，增加了一条双向链表，使得上面的结构可以保持键值对的插入顺序。同时通过对链表进行相应的操作，实现了访问顺序相关逻辑。详细可以查看："),e("a",x,[o("《LinkedHashMap 源码详细分析（JDK1.8）》"),a(t)])]),g,S])])}const q=l(r,[["render",v],["__file","index.html.vue"]]);export{q as default};
